"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[1123],{5103(e,t,n){n.r(t),n.d(t,{assets:()=>r,contentTitle:()=>a,default:()=>u,frontMatter:()=>h,metadata:()=>i,toc:()=>l});const i=JSON.parse('{"id":"stoicism/marcus-aurelius/meditations/meditations-book-12","title":"Meditations \u2014 Book 12","description":"Book 12","source":"@site/docs/stoicism/marcus-aurelius/meditations/meditations-book-12.md","sourceDirName":"stoicism/marcus-aurelius/meditations","slug":"/stoicism/marcus-aurelius/meditations/meditations-book-12","permalink":"/justinus/docs/stoicism/marcus-aurelius/meditations/meditations-book-12","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":13,"frontMatter":{"sidebar_position":13,"title":"Meditations \u2014 Book 12","sidebar_label":"Book 12"},"sidebar":"philosophersSidebar","previous":{"title":"Book 11","permalink":"/justinus/docs/stoicism/marcus-aurelius/meditations/meditations-book-11"},"next":{"title":"Epictetus","permalink":"/justinus/docs/stoicism/epictetus/"}}');var o=n(4848),s=n(8453);const h={sidebar_position:13,title:"Meditations \u2014 Book 12",sidebar_label:"Book 12"},a="Meditations",r={},l=[{value:"Book 12",id:"book-12",level:2},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function d(e){const t={em:"em",h1:"h1",h2:"h2",header:"header",p:"p",strong:"strong",...(0,s.R)(),...e.components},{Details:n}=t;return n||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,o.jsxs)(o.Fragment,{children:[(0,o.jsxs)("div",{style:{textAlign:"center"},children:[(0,o.jsx)(t.header,{children:(0,o.jsx)(t.h1,{id:"meditations",children:"Meditations"})}),(0,o.jsx)(t.h2,{id:"book-12",children:"Book 12"})]}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.em,{children:"Translated by George Long"})}),"\n",(0,o.jsxs)(n,{open:!0,children:[(0,o.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,o.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,o.jsx)(t.p,{children:"Book 12 is the final book, and it reads like one \u2014 a gathering of threads, a quieter tone, and a sense of arriving somewhere."}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"Everything you want is available right now"})," \u2014 The opening is almost a release. All the things you've been circling toward by complicated routes are already here, if you stop refusing them to yourself. Forget the past, trust the future to providence, direct the present toward piety and justice. That's the whole path, stated plainly."]}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"You are three things"})," \u2014 Body, breath, intelligence. The first two are yours to care for but not truly you. Only the intelligence is properly yours. Separate that from everything else \u2014 past, future, bodily sensation, other people's opinions \u2014 make it like Empedocles' sphere, round and resting in itself, and live only the present. Then you can pass whatever remains of life free from perturbation."]}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"A quiet observation on vanity"})," \u2014 Every man loves himself more than anyone else, yet values his own opinion of himself less than the opinion of strangers. If a god told you to think nothing you wouldn't immediately say aloud, you couldn't last a day. We are more afraid of our neighbor's judgement than our own."]}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"On the gods and immortality"})," \u2014 One of the rare moments where Marcus genuinely wrestles with doubt. If good men are simply extinguished at death, why? He answers himself: if it ought to have been otherwise, the gods would have made it so. This is faith by logical elimination rather than comfort \u2014 characteristically Marcus."]}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"Either necessity, providence, or chaos \u2014 it doesn't matter"})," \u2014 The argument from Book 4 reprised as a final verdict. If necessity, stop resisting. If providence, make yourself worthy of it. If chaos, then at least your intelligence remains your own even as the storm carries everything else away."]}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"Does the lamp lose its splendor before it's extinguished?"})," \u2014 One of his most beautiful lines. Then: shall truth, justice, and temperance in you be extinguished before death comes? The implication is no \u2014 keep them burning to the end."]}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"Death at the proper time is no evil"})," \u2014 A final, careful argument: an act that ends at its proper time suffers no harm from ending. Life is a series of acts. If it ends at its proper time \u2014 which nature fixes, as it fixes all things \u2014 then it too suffers no harm. The universe stays young through constant change. Your ending is part of that."]}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"Cast away opinion: thou art saved"})," \u2014 The most compressed version of his entire philosophy. One sentence. Then: who hinders you from doing this?"]}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"When you're troubled, here's what you've forgotten"})," \u2014 A remarkable inventory of forgetting: that everything happens according to universal nature; that another's wrong act is nothing to you; that everything always happened this way and always will; how close your kinship is to all humanity; that every man's intelligence is an efflux of the divine; that nothing is truly yours \u2014 not your child, not your body, not your soul; that everything is opinion; and finally that you live only the present moment and lose only that."]}),(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"The final note"})," \u2014 Smoke and ash and a tale, or not even a tale. All the conspicuous men, all the great sufferers and strivers \u2014 where are they? He trails off mid-sentence, as if the point no longer needs finishing."]}),(0,o.jsx)(t.p,{children:"It's a fitting end \u2014 not a conclusion so much as a fading out, which is exactly what Marcus would have wanted."})]}),"\n",(0,o.jsxs)(n,{open:!0,children:[(0,o.jsx)("summary",{children:"Text"}),(0,o.jsx)(t.h2,{id:"text",children:"Text"}),(0,o.jsx)(t.p,{children:"All those things at which thou wishest to arrive by a circuitous\nroad, thou canst have now, if thou dost not refuse them to thyself.\nAnd this means, if thou wilt take no notice of all the past, and trust\nthe future to providence, and direct the present only conformably\nto piety and justice. Conformably to piety, that thou mayest be content\nwith the lot which is assigned to thee, for nature designed it for\nthee and thee for it. Conformably to justice, that thou mayest always\nspeak the truth freely and without disguise, and do the things which\nare agreeable to law and according to the worth of each. And let neither\nanother man's wickedness hinder thee, nor opinion nor voice, nor yet\nthe sensations of the poor flesh which has grown about thee; for the\npassive part will look to this. If then, whatever the time may be\nwhen thou shalt be near to thy departure, neglecting everything else\nthou shalt respect only thy ruling faculty and the divinity within\nthee, and if thou shalt be afraid not because thou must some time\ncease to live, but if thou shalt fear never to have begun to live\naccording to nature- then thou wilt be a man worthy of the universe\nwhich has produced thee, and thou wilt cease to be a stranger in thy\nnative land, and to wonder at things which happen daily as if they\nwere something unexpected, and to be dependent on this or that."}),(0,o.jsx)(t.p,{children:"God sees the minds (ruling principles) of all men bared of the material\nvesture and rind and impurities. For with his intellectual part alone\nhe touches the intelligence only which has flowed and been derived\nfrom himself into these bodies. And if thou also usest thyself to\ndo this, thou wilt rid thyself of thy much trouble. For he who regards\nnot the poor flesh which envelops him, surely will not trouble himself\nby looking after raiment and dwelling and fame and such like externals\nand show."}),(0,o.jsx)(t.p,{children:"The things are three of which thou art composed, a little body, a\nlittle breath (life), intelligence. Of these the first two are thine,\nso far as it is thy duty to take care of them; but the third alone\nis properly thine. Therefore if thou shalt separate from thyself,\nthat is, from thy understanding, whatever others do or say, and whatever\nthou hast done or said thyself, and whatever future things trouble\nthee because they may happen, and whatever in the body which envelops\nthee or in the breath (life), which is by nature associated with the\nbody, is attached to thee independent of thy will, and whatever the\nexternal circumfluent vortex whirls round, so that the intellectual\npower exempt from the things of fate can live pure and free by itself,\ndoing what is just and accepting what happens and saying the truth:\nif thou wilt separate, I say, from this ruling faculty the things\nwhich are attached to it by the impressions of sense, and the things\nof time to come and of time that is past, and wilt make thyself like\nEmpedocles' sphere,"}),(0,o.jsx)(t.p,{children:"All round, and in its joyous rest reposing; and if thou shalt strive\nto live only what is really thy life, that is, the present- then thou\nwilt be able to pass that portion of life which remains for thee up\nto the time of thy death, free from perturbations, nobly, and obedient\nto thy own daemon (to the god that is within thee)."}),(0,o.jsx)(t.p,{children:"I have often wondered how it is that every man loves himself more\nthan all the rest of men, but yet sets less value on his own opinion\nof himself than on the opinion of others. If then a god or a wise\nteacher should present himself to a man and bid him to think of nothing\nand to design nothing which he would not express as soon as he conceived\nit, he could not endure it even for a single day. So much more respect\nhave we to what our neighbours shall think of us than to what we shall\nthink of ourselves."}),(0,o.jsx)(t.p,{children:"How can it be that the gods after having arranged all things well\nand benevolently for mankind, have overlooked this alone, that some\nmen and very good men, and men who, as we may say, have had most communion\nwith the divinity, and through pious acts and religious observances\nhave been most intimate with the divinity, when they have once died\nshould never exist again, but should be completely extinguished?"}),(0,o.jsx)(t.p,{children:"But if this is so, be assured that if it ought to have been otherwise,\nthe gods would have done it. For if it were just, it would also be\npossible; and if it were according to nature, nature would have had\nit so. But because it is not so, if in fact it is not so, be thou\nconvinced that it ought not to have been so:- for thou seest even\nof thyself that in this inquiry thou art disputing with the diety;\nand we should not thus dispute with the gods, unless they were most\nexcellent and most just;- but if this is so, they would not have allowed\nanything in the ordering of the universe to be neglected unjustly\nand irrationally."}),(0,o.jsx)(t.p,{children:"Practise thyself even in the things which thou despairest of accomplishing.\nFor even the left hand, which is ineffectual for all other things\nfor want of practice, holds the bridle more vigorously than the right\nhand; for it has been practised in this."}),(0,o.jsx)(t.p,{children:"Consider in what condition both in body and soul a man should be when\nhe is overtaken by death; and consider the shortness of life, the\nboundless abyss of time past and future, the feebleness of all matter."}),(0,o.jsx)(t.p,{children:"Contemplate the formative principles (forms) of things bare of their\ncoverings; the purposes of actions; consider what pain is, what pleasure\nis, and death, and fame; who is to himself the cause of his uneasiness;\nhow no man is hindered by another; that everything is opinion."}),(0,o.jsx)(t.p,{children:"In the application of thy principles thou must be like the pancratiast,\nnot like the gladiator; for the gladiator lets fall the sword which\nhe uses and is killed; but the other always has his hand, and needs\nto do nothing else than use it."}),(0,o.jsx)(t.p,{children:"See what things are in themselves, dividing them into matter, form\nand purpose."}),(0,o.jsx)(t.p,{children:"What a power man has to do nothing except what God will approve, and\nto accept all that God may give him."}),(0,o.jsx)(t.p,{children:"With respect to that which happens conformably to nature, we ought\nto blame neither gods, for they do nothing wrong either voluntarily\nor involuntarily, nor men, for they do nothing wrong except involuntarily.\nConsequently we should blame nobody."}),(0,o.jsx)(t.p,{children:"How ridiculous and what a stranger he is who is surprised at anything\nwhich happens in life."}),(0,o.jsx)(t.p,{children:"Either there is a fatal necessity and invincible order, or a kind\nProvidence, or a confusion without a purpose and without a director\n(Book IV). If then there is an invincible necessity, why dost thou\nresist? But if there is a Providence which allows itself to be propitiated,\nmake thyself worthy of the help of the divinity. But if there is a\nconfusion without governor, be content that in such a tempest thou\nhast in thyself a certain ruling intelligence. And even if the tempest\ncarry thee away, let it carry away the poor flesh, the poor breath,\neverything else; for the intelligence at least it will not carry away."}),(0,o.jsx)(t.p,{children:"Does the light of the lamp shine without losing its splendour until\nit is extinguished; and shall the truth which is in thee and justice\nand temperance be extinguished before thy death?"}),(0,o.jsx)(t.p,{children:"When a man has presented the appearance of having done wrong, say,\nHow then do I know if this is a wrongful act? And even if he has done\nwrong, how do I know that he has not condemned himself? and so this\nis like tearing his own face. Consider that he, who would not have\nthe bad man do wrong, is like the man who would not have the fig-tree\nto bear juice in the figs and infants to cry and the horse to neigh,\nand whatever else must of necessity be. For what must a man do who\nhas such a character? If then thou art irritable, cure this man's\ndisposition."}),(0,o.jsx)(t.p,{children:"If it is not right, do not do it: if it is not true, do not say it.\nFor let thy efforts be-"}),(0,o.jsx)(t.p,{children:"In everything always observe what the thing is which produces for\nthee an appearance, and resolve it by dividing it into the formal,\nthe material, the purpose, and the time within which it must end."}),(0,o.jsx)(t.p,{children:"Perceive at last that thou hast in thee something better and more\ndivine than the things which cause the various affects, and as it\nwere pull thee by the strings. What is there now in my mind? Is it\nfear, or suspicion, or desire, or anything of the kind?"}),(0,o.jsx)(t.p,{children:"First, do nothing inconsiderately, nor without a purpose. Second,\nmake thy acts refer to nothing else than to a social end."}),(0,o.jsx)(t.p,{children:"Consider that before long thou wilt be nobody and nowhere, nor will\nany of the things exist which thou now seest, nor any of those who\nare now living. For all things are formed by nature to change and\nbe turned and to perish in order that other things in continuous succession\nmay exist."}),(0,o.jsx)(t.p,{children:"Consider that everything is opinion, and opinion is in thy power.\nTake away then, when thou choosest, thy opinion, and like a mariner,\nwho has doubled the promontory, thou wilt find calm, everything stable,\nand a waveless bay."}),(0,o.jsx)(t.p,{children:"Any one activity whatever it may be, when it has ceased at its proper\ntime, suffers no evil because it has ceased; nor he who has done this\nact, does he suffer any evil for this reason that the act has ceased.\nIn like manner then the whole which consists of all the acts, which\nis our life, if it cease at its proper time, suffers no evil for this\nreason that it has ceased; nor he who has terminated this series at\nthe proper time, has he been ill dealt with. But the proper time and\nthe limit nature fixes, sometimes as in old age the peculiar nature\nof man, but always the universal nature, by the change of whose parts\nthe whole universe continues ever young and perfect. And everything\nwhich is useful to the universal is always good and in season. Therefore\nthe termination of life for every man is no evil, because neither\nis it shameful, since it is both independent of the will and not opposed\nto the general interest, but it is good, since it is seasonable and\nprofitable to and congruent with the universal. For thus too he is\nmoved by the deity who is moved in the same manner with the deity\nand moved towards the same things in his mind."}),(0,o.jsx)(t.p,{children:"These three principles thou must have in readiness. In the things\nwhich thou doest do nothing either inconsiderately or otherwise than\nas justice herself would act; but with respect to what may happen\nto thee from without, consider that it happens either by chance or\naccording to Providence, and thou must neither blame chance nor accuse\nProvidence. Second, consider what every being is from the seed to\nthe time of its receiving a soul, and from the reception of a soul\nto the giving back of the same, and of what things every being is\ncompounded and into what things it is resolved. Third, if thou shouldst\nsuddenly be raised up above the earth, and shouldst look down on human\nthings, and observe the variety of them how great it is, and at the\nsame time also shouldst see at a glance how great is the number of\nbeings who dwell around in the air and the aether, consider that as\noften as thou shouldst be raised up, thou wouldst see the same things,\nsameness of form and shortness of duration. Are these things to be\nproud of?"}),(0,o.jsx)(t.p,{children:"Cast away opinion: thou art saved. Who then hinders thee from casting\nit away?"}),(0,o.jsx)(t.p,{children:"When thou art troubled about anything, thou hast forgotten this, that\nall things happen according to the universal nature; and forgotten\nthis, that a man's wrongful act is nothing to thee; and further thou\nhast forgotten this, that everything which happens, always happened\nso and will happen so, and now happens so everywhere; forgotten this\ntoo, how close is the kinship between a man and the whole human race,\nfor it is a community, not of a little blood or seed, but of intelligence.\nAnd thou hast forgotten this too, that every man's intelligence is\na god, and is an efflux of the deity; and forgotten this, that nothing\nis a man's own, but that his child and his body and his very soul\ncame from the deity; forgotten this, that everything is opinion; and\nlastly thou hast forgotten that every man lives the present time only,\nand loses only this."}),(0,o.jsx)(t.p,{children:"Constantly bring to thy recollection those who have complained greatly\nabout anything, those who have been most conspicuous by the greatest\nfame or misfortunes or enmities or fortunes of any kind: then think\nwhere are they all now? Smoke and ash and a tale, or not even a tale.\nAnd let there be present to thy mind also everything of this sort,\nhow Fabius Catullinus lived in the country, and Lucius Lupus in his\ngardens, and Stertinius at Baiae, and Tiberius at Capreae and Velius\nRufus (or Rufus at Velia); and in fine think of the eager pursuit\nof anything conjoined with pride; and how worthless everything is\nafter which men violently strain; and how much more philosophical\nit is for a man in the opportunities presented to him to show"}),(0,o.jsx)(t.p,{children:"THE END"})]})]})}function u(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},8453(e,t,n){n.d(t,{R:()=>h,x:()=>a});var i=n(6540);const o={},s=i.createContext(o);function h(e){const t=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:h(e.components),i.createElement(s.Provider,{value:t},e.children)}}}]);